```javascript
// Exemplo de código em Javascript para criar um objeto e realizar operações básicas

// Criar um objeto
let pessoa = {
  nome: "Eduh Dev",
  idade: 30,
  cidade: "São Paulo"
};

// Função para imprimir informações do objeto
function imprimirInformacoes(pessoa) {
  console.log(`Nome: ${pessoa.nome}`);
  console.log(`Idade: ${pessoa.idade}`);
  console.log(`Cidade: ${pessoa.cidade}`);
}

// Chamar a função para imprimir informações
imprimirInformacoes(pessoa);

// Alterar uma propriedade do objeto
pessoa.idade = 31;

// Imprimir informações atualizadas
console.log("Informações atualizadas:");
imprimirInformacoes(pessoa);
```
